package com.granpa.pumpselector;
import android.app.*;import android.os.*;import android.widget.*;import java.util.*;
public class QAActivity extends Activity{protected void onCreate(Bundle b){super.onCreate(b);LinearLayout root=Ui.root(this);root.addView(Ui.text(this,"Catalogue data QA",26,Ui.TEXT,1));add(root,"TEXMO",PumpRepository.TEXMO_ASSET);add(root,"LUBI",PumpRepository.LUBI_ASSET);add(root,"KSB",PumpRepository.KSB_ASSET);root.addView(Ui.text(this,"Models marked Needs review remain visible in catalogue search but are excluded from automatic duty-point recommendations and comparison.",13,Ui.MUTED,0));setContentView(Ui.scroll(this,root));}void add(LinearLayout root,String brand,String asset){ArrayList<PumpRecord>r=PumpRepository.getRecords(this,asset);int ok=0,fixed=0,review=0;HashSet<String>cats=new HashSet<>();for(PumpRecord p:r){cats.add(p.category);if(!p.selectable||"NEEDS_REVIEW".equals(p.dataStatus))review++;else if("AUTO_FIXED".equals(p.dataStatus))fixed++;else ok++;}LinearLayout c=Ui.card(this);c.addView(Ui.text(this,brand,21,Ui.BLUE,1));c.addView(Ui.text(this,r.size()+" records • "+cats.size()+" detailed categories",14,Ui.MUTED,0));c.addView(Ui.text(this,"Checked: "+ok+"   Auto-fixed: "+fixed+"   Needs review: "+review,15,review>0?Ui.ORANGE:Ui.GREEN,1));root.addView(c);}}